import React from 'react'
import styled from 'styled-components'
import Loading from '../../components/Loading'
import facebook from '../../images/logos/facebook.jpg'
import twitter from '../../images/logos/twitter.jpg'
import netflix from '../../images/logos/netflix.jpg'
import paypal from '../../images/logos/paypal.jpg'
import github from '../../images/logos/github.jpg'
import header from '../../images/header.jpg'
import InfoOutlinedIcon from '@material-ui/icons/InfoOutlined';
import CheckCircleIcon from '@material-ui/icons/CheckCircle';
import illustration from '../../images/illustration-buy.png'
import BuySection from './BuySection'


export default function Shoppage() {
    return (
        <>
            <Loading/>
            <Container>
                <Header>
                </Header>
                <Wrapper>
                    <Title>
                        <Image src={illustration} alt="illustration" />
                        <InfoOutlinedIcon/><span>De știut...</span>
                    </Title>
                    <Ul>
                        <Li><CheckCircleIcon/> 
                            Toate proiectele folosesc limbajul de programare ReactJS, o bibliotecă JavaScript întreținută de Facebook și folosită de site-uri ca bineînțeles <a href="https://www.facebook.com/" target="_blank" rel="noreferrer">Facebook <Img src={facebook} alt="facebook logo"/></a>, <a href="https://twitter.com/home" target="_blank" rel="noreferrer">Twitter <Img src={twitter} alt="twitter logo"/></a>, <a href="https://www.netflix.com/ro-en/" target="_blank" rel="noreferrer">Netflix <Img src={netflix} alt="netflix logo"/></a>, <a href="https://www.paypal.com/ro/home" target="_blank" rel="noreferrer">PayPal <Img src={paypal} alt="paypal logo"/></a> și mulți alții.
                        </Li>
                        <Li><CheckCircleIcon/>
                            Optimizare SEO (Search Engine Optimization) - Optimizare pentru vizibilitatea și descoperirea  site-ului pe motoarele de căutare precum Google, Bing, Yahoo, etc. atât cât și optimizarea acestuia atunci când este distribuit pe rețelele de socializare ca Facebook și Twitter.
                        </Li>
                        <Li><CheckCircleIcon/> 
                            Hosting (Găzduire web - uploadare fișiere) - este gratuită pe contul meu de <a href="https://github.com/codmitu" target="_blank" rel="noreferrer">Github <Img src={github} alt="github logo"/></a>, dar se poate găzdui și pe alte site-uri contra cost la cerere.
                        </Li>
                        <Li><CheckCircleIcon/> 
                            Domeniul (ex: www.domeniu.ro) - contra cost, prețurile variază in funcție de domeniu: .ro (40 RON), .com (50 RON), .info (80 RON), etc. Acestea se înregistrează pe <a href="https://www.datahost.ro/" target="_blank" rel="noreferrer">datahost.ro</a>, sau domeniu gratuit pe contul meu de <a href="https://github.com/codmitu" target="_blank" rel="noreferrer">Github <Img src={github} alt="github logo"/></a> (ex: www.codmitu.github.io/siteul-tau).
                        </Li>
                        <Li><CheckCircleIcon/> 
                            Certificat SSL la nevoie - de la 50 RON/an de pe <a href="https://www.datahost.ro/" target="_blank" rel="noreferrer">datahost.ro</a>.
                        </Li>
                        <Li><CheckCircleIcon/> 
                            Business Email - Email personalizat (Gmail), 26 RON/lună, acesta se înregistrează pe <a href="https://www.datahost.ro/" target="_blank" rel="noreferrer">datahost.ro</a>.
                        </Li>
                        <Li><CheckCircleIcon/> 
                            Mentenanță și modificare text/imagini gratuit o dată pe săptămână.
                        </Li>
                        <Li><CheckCircleIcon/> 
                            Adăugare alte pagini, widgeturi, caracteristici după publicarea websitului - contra cost de la 50 RON în funcție de complexitate.
                        </Li>
                    </Ul>
                </Wrapper>

                <BuySection/>
            </Container>
        </>
    )
}


const Container = styled.article`
    position: relative;
`
const Header = styled.header`
    background: url(${header}) no-repeat bottom center / cover;
    height: 300px;
    width: 100%;
    opacity: 0.3;
    position: absolute;
`
const Wrapper = styled.section`
    display: flex;
    justify-content: space-around;
    max-width: 1500px;
    margin: 0 auto;
    padding: 100px 0 0;
    position: relative;
    @media screen and (max-width: 900px) {
        flex-direction: column;
        gap: 30px;
    }
`
const Title = styled.div`
    font-size: var(--bf);
    font-weight: 500;
    font-family: var(--fsc);
    display: flex;
    align-items: flex-start;
    justify-content: center;
    flex: 0.5;
    color: #444444;
    position: relative;
    >span {
        position: relative;
        &::after {
            position: absolute;
            content: '';
            bottom: -20px;
            right: 50px;
            width: 100px;
            height: 2px;
            background-color: var(--cbd);
        }
    }
    >svg {
        font-size: var(--bf);
        margin-top: 7px;
        color: var(--cbd);
        @media screen and (max-width: 700px) {
            margin-top: 4px;
        }
    }
`
const Image = styled.img`
    width: 700px;
    position: absolute;
    top: 300px;
    left: -5vw;
    z-index: -1;
    @media screen and (max-width: 900px) {
        display: none;
    }
`
const Ul = styled.ul`
    flex: 0.5;
    background-color: #fafafad2;
    padding: 2vw 5vw;
    border-radius: 5px;
`
const Li = styled.li`
    margin: 15px 0;
    line-height: 2;
    font-size: var(--sf);
    list-style: none;
    >svg {
        color: var(--cgd);
        font-size: var(--sf);
        margin-bottom: -3px;
    }
    >a {
        color: var(--cbd);
        text-decoration: none;
        &:hover {
            color: var(--cbl);
        }
    }
`
const Img = styled.img`
    max-height: 1rem;
    vertical-align: baseline;
    border-radius: 3px;
`
