import { FormHelperText } from '@material-ui/core';
import { Button } from '@material-ui/core';
import { FormControlLabel } from '@material-ui/core';
import { FormLabel } from '@material-ui/core';
import { RadioGroup } from '@material-ui/core';
import { Radio } from '@material-ui/core';
import React from 'react'
import { useState } from 'react';
import styled from 'styled-components'
import DoneIcon from '@material-ui/icons/Done';
import tile from '../../images/tile.png'

export default function BuySection() {
    const [value, setValue] = useState('basic');
    const [helperText, setHelperText] = useState('Choose wisely');

    const handleRadioChange = (event, text) => {
        setValue(event.target.value || text);
        setHelperText(' ');
    };

    const handleSubmit = (event) => {
        event.preventDefault();
    
        if (value === 'best') {
          setHelperText('You got it!');
        } else if (value === 'worst') {
          setHelperText('Sorry, wrong answer!');
        } else {
          setHelperText('Please select an option.');
        }
    };

    return (
        <Container>
             <Form onSubmit={handleSubmit}>
                <MyFormLabel component="legend">Alege Pachet</MyFormLabel>
                <MyRadioGroup aria-label="quiz" name="quiz" value={value} onChange={handleRadioChange}>
                    <Wrapper onClick={e => handleRadioChange(e, 'basic')} 
                    style={{ color: (value === "basic" ? '' : 'grey'), borderColor: (value === "basic" ? '#84c219' : '')}}>
                        <FormControlLabel value="basic" 
                        control={<BasicRadio name="basic" />} 
                        label="Pachet Basic"/>
                        <Ul>
                            <Lig><DoneIcon/> Pagini: 1</Lig>
                            <Lig><DoneIcon/> Design responsive</Lig>
                            <Lig><DoneIcon/> Formular de contact pe e-mail</Lig>
                            <Lig><DoneIcon/> Hosting Gratuit</Lig>
                            <Lig><DoneIcon/> Optimizare SEO</Lig>
                        </Ul>
                    </Wrapper>
                    <Wrapper onClick={e => handleRadioChange(e, 'average')} 
                    style={{ color: (value === "average" ? '' : 'grey'), borderColor: (value === "average" ? '#2F85AD' : '')}}>
                        <FormControlLabel value="average" 
                        control={<AverageRadio name="average" />}
                        label="Pachet Basic Plus" />
                        <Ul>
                            <Lib><DoneIcon/> Pagini: 2 - 10</Lib>
                            <Lib><DoneIcon/> Design responsive</Lib>
                            <Lib><DoneIcon/> Formular de contact pe e-mail</Lib>
                            <Lib><DoneIcon/> Hosting Gratuit</Lib>
                            <Lib><DoneIcon/> Optimizare SEO</Lib>
                        </Ul>
                    </Wrapper>
                    <Wrapper onClick={e => handleRadioChange(e, 'full')}
                    style={{ color: (value === "full" ? '' : 'grey'), borderColor: (value === "full" ? '#AD2638' : '')}}>
                        <FormControlLabel value="full" 
                        control={<FullRadio name="full"/>} 
                        label="Pachet Full" />
                        <Ul>
                            <Lir><DoneIcon/> Pagini: nelimitate</Lir>
                            <Lir><DoneIcon/> Design responsive</Lir>
                            <Lir><DoneIcon/> Formular de contact</Lir>
                            <Lir><DoneIcon/> Review-uri clienți</Lir>
                            <Lir><DoneIcon/> Autentificare Google client/admin</Lir>
                            <Lir><DoneIcon/> Adăugare/ștergere produse</Lir>
                            <Lir><DoneIcon/> Încărcare imagini produse</Lir>
                            <Lir><DoneIcon/> Produse unice nelimitate</Lir>
                            <Lir><DoneIcon/> Hosting Gratuit</Lir>
                            <Lir><DoneIcon/> Optimizare SEO</Lir>
                        </Ul>
                    </Wrapper>
                </MyRadioGroup>


                <FormHelperText>{helperText}</FormHelperText>
                <Button type="submit" variant="outlined" color="primary">
                    Check Answer
                </Button>
            </Form>
        </Container>
    )
}


const Container = styled.section`
    padding: 10px 0;
    background: url(${tile});
`
const Form = styled.form`
    width: 1500px;
    max-width: 100vw;
    margin: 100px auto;
`
const MyFormLabel = styled(FormLabel)`
    font-size: var(--bf) !important;
    font-weight: 300 !important;
    color: #3a3a3a !important;
    font-family: var(--fsc) !important;
    position: relative !important;
    margin: 150px  0 100px 100px;
    &::after {
        position: absolute;
        content: '';
        bottom: -20px;
        left: 150px;
        width: 200px;
        height: 2px;
        background-color: var(--cbd);
    }
    @media screen and (max-width: 500px) {
        margin: 0 0 50px 20px;
        &::after {
            width: 150px;
        }
    }
`
const MyRadioGroup = styled(RadioGroup)`
    display: flex !important;
    flex-direction: row !important;
    align-items: stretch;
    justify-content: space-evenly;
    margin-bottom: 100px;
    flex-wrap: wrap;
    gap: 50px;
`
const Wrapper = styled.div`
    cursor: pointer;
    border: 5px solid lightgray;
    background: #ffffff;
    padding: 5px 20px 20px;
    border-radius: 10px;
    transition: all 0.5s ease-out;
    position: relative;
    &::after {
        position: absolute;
        content: '';
        bottom: -100px;
        left: 0;
        width: 100%;
        height: 50px;
        border-radius: 50%;
        background: radial-gradient(closest-side at 50%, black 10%, transparent);
        transition: all 0.5s ease-out;
        opacity: 0.3;
    }
    &:hover {
        transform: translateY(-10px);
        &::after {
            transform: translateY(10px);
            opacity: 0.2;
        }
    }
    >label >span{
        font-weight: 600;
    }
`
const BasicRadio = styled(Radio)`
    color: var(--cgd) !important;
`
const AverageRadio = styled(Radio)`
    color: var(--cbd) !important;
`
const FullRadio = styled(Radio)`
    color: var(--crd) !important;
`
const Ul = styled.ul`
    list-style: none;
    font-size: var(--sf);
    line-height: 1.7;
`
const Lig = styled.li`
    >svg {
        color: var(--cgd);
    }
`
const Lib = styled.li`
    >svg {
        color: var(--cbd);
    }
`
const Lir = styled.li`
    >svg {
        color: var(--crd);
    }
`
