import React from 'react'
import styled from 'styled-components'
import {motion} from 'framer-motion'


export default function Loading() {
    const variants = {
        visible: { opacity: 1 },
        hidden: { opacity: 0, pointerEvents: 'none'},
    }

    const circle = {
        small: {scale: 0},
        big: {scale: 1}
    }

    return (
        <Container as={motion.div} initial="visible" animate="hidden" variants={variants} transition={{ duration: 0.2,delay: 1}}>
            <Circle as={motion.div} initial="small" animate="big" variants={circle} transition={{duration: 1}}></Circle>
        </Container>
    )
}


const Container = styled.div`
    position: fixed;
    inset: 0;
    background-color: var(--cbl);
    z-index: 69;
    display: grid;
    place-items: center;
`
const Circle = styled.div`
    position: absolute;
    width: 120vw;
    height: 120vw;
    border-radius: 50%;
    background-color: #b3ed5088;
    @media screen and (max-width: 1440px) {
        width: 150vw;
        height: 150vw;
    }
    @media screen and (max-width: 850px) {
        width: 150vh;
        height: 150vh;
    }
`